const fs = require('fs');
const path = '/tmp/competitor-tracker-fix/all-competitors.json';
const data = JSON.parse(fs.readFileSync(path, 'utf8'));
const triggerTime = new Date().toISOString();

let priorityFilter = 'ALL';
const scheduleName = $input.first().json.scheduleName || '';

if (scheduleName.includes('CRITICAL')) priorityFilter = 'CRITICAL';
else if (scheduleName.includes('HIGH')) priorityFilter = 'HIGH';
else if (scheduleName.includes('MEDIUM')) priorityFilter = 'MEDIUM';
else if (scheduleName.includes('LOW')) priorityFilter = 'LOW';

const allCompetitors = [];
for (const [category, competitors] of Object.entries(data.competitors)) {
  for (const comp of competitors) {
    if (priorityFilter === 'ALL' || comp.priority === priorityFilter) {
      allCompetitors.push({
        ...comp,
        category,
        scanTimestamp: triggerTime
      });
    }
  }
}

return allCompetitors.map(c => ({ json: c }));

const items = $input.all();
const previousResults = {};

try {
  const fs = require('fs');
  const path = '/tmp/competitor-tracker-fix/competitor-research-results.json';
  if (fs.existsSync(path)) {
    const raw = fs.readFileSync(path, 'utf8');
    const parsed = JSON.parse(raw);
    previousResults.lastScan = parsed.last_scan;
    previousResults.competitors = parsed.competitors || {};
  }
} catch (e) {
  console.log('No previous results found');
}

const updates = [];
const now = new Date();

for (const item of items) {
  const comp = item.json;
  const name = comp.name;
  const category = comp.category;
  const priority = comp.priority;
  const repo = comp.repo || '';
  const lastScan = previousResults.lastScan;

  if (comp.commits && Array.isArray(comp.commits)) {
    for (const commit of comp.commits.slice(0, 5)) {
      const commitDate = new Date(commit.commit?.author?.date || commit.sha);
      if (!lastScan || commitDate > new Date(lastScan)) {
        const sha = (commit.sha || '').substring(0, 7);
        const message = (commit.commit?.message || '').split('\n')[0];
        const author = commit.commit?.author?.name || 'unknown';
        updates.push({
          json: {
            name,
            category,
            priority,
            update_type: 'commit',
            title: `${author}: ${message}`,
            description: `Commit ${sha} by ${author}`,
            url: `https://github.com/${repo}/commit/${sha}`,
            timestamp: commit.commit?.author?.date || now.toISOString(),
            significance: priority === 'CRITICAL' ? 'high' : 'medium'
          }
        });
      }
    }
  }

  if (comp.releases && Array.isArray(comp.releases)) {
    for (const release of comp.releases.slice(0, 3)) {
      const pubDate = new Date(release.published_at);
      if (!lastScan || pubDate > new Date(lastScan)) {
        updates.push({
          json: {
            name,
            category,
            priority,
            update_type: 'release',
            title: `Release ${release.tag_name}`,
            description: (release.body || '').substring(0, 200),
            url: release.html_url,
            timestamp: release.published_at,
            significance: 'critical'
          }
        });
      }
    }
  }

  if (comp.prs && Array.isArray(comp.prs)) {
    for (const pr of comp.prs.slice(0, 5)) {
      if (pr.merged_at) {
        const mergeDate = new Date(pr.merged_at);
        if (!lastScan || mergeDate > new Date(lastScan)) {
          updates.push({
            json: {
              name,
              category,
              priority,
              update_type: 'pr',
              title: `PR merged: ${pr.title}`,
              description: `PR #${pr.number} by ${pr.user?.login}`,
              url: pr.html_url,
              timestamp: pr.merged_at,
              significance: 'medium'
            }
          });
        }
      }
    }
  }

  if (comp.issues && Array.isArray(comp.issues)) {
    for (const issue of comp.issues.slice(0, 5)) {
      if (!issue.pull_request && issue.closed_at) {
        const closeDate = new Date(issue.closed_at);
        if (!lastScan || closeDate > new Date(lastScan)) {
          updates.push({
            json: {
              name,
              category,
              priority,
              update_type: 'issue',
              title: `Feature: ${issue.title}`,
              description: `Issue #${issue.number} closed`,
              url: issue.html_url,
              timestamp: issue.closed_at,
              significance: 'low'
            }
          });
        }
      }
    }
  }

  if (comp.stars !== undefined) {
    const milestones = [1000, 5000, 10000, 25000, 50000, 100000, 200000, 500000];
    const prevStars = previousResults.competitors?.[name]?.stars || 0;
    for (const milestone of milestones) {
      if (prevStars < milestone && comp.stars >= milestone) {
        updates.push({
          json: {
            name,
            category,
            priority,
            update_type: 'star_milestone',
            title: `\u2b50 ${comp.stars} stars! (crossed ${milestone} milestone)`,
            description: `Reached ${comp.stars} GitHub stars`,
            url: `https://github.com/${repo}/stargazers`,
            timestamp: now.toISOString(),
            significance: 'high'
          }
        });
        break;
      }
    }
  }

  if (comp.changelog_changed) {
    updates.push({
      json: {
        name,
        category,
        priority,
        update_type: 'changelog',
        title: 'Changelog updated',
        description: `Changelog page changed: ${comp.changelog}`,
        url: comp.changelog,
        timestamp: now.toISOString(),
        significance: 'medium'
      }
    });
  }
}

return updates;

const items = $input.all();

const report = {
  last_scan: new Date().toISOString(),
  total_updates: items.length,
  critical_updates: [],
  high_updates: [],
  medium_updates: [],
  low_updates: [],
  competitors: {}
};

for (const item of items) {
  const update = item.json;
  const significance = update.significance || 'low';

  if (significance === 'critical') report.critical_updates.push(update);
  else if (significance === 'high') report.high_updates.push(update);
  else if (significance === 'medium') report.medium_updates.push(update);
  else report.low_updates.push(update);

  if (!report.competitors[update.name]) {
    report.competitors[update.name] = {
      name: update.name,
      category: update.category,
      priority: update.priority,
      updates: []
    };
  }
  report.competitors[update.name].updates.push(update);
}

return [{ json: report }];

const report = $input.first().json;

let msg = '\ud83d\udd0d OpenSIN Competitor Intelligence Report\n';
msg += '\ud83d\udcc5 ' + report.last_scan.substring(0, 10) + '\n';
msg += '\ud83d\udcca ' + report.total_updates + ' updates found\n\n';

if (report.critical_updates.length > 0) {
  msg += '\ud83d\udea8 CRITICAL:\n';
  for (const u of report.critical_updates) {
    msg += '  \u2022 ' + u.name + ': ' + u.title + '\n';
  }
  msg += '\n';
}

if (report.high_updates.length > 0) {
  msg += '\u26a0\ufe0f HIGH:\n';
  for (const u of report.high_updates) {
    msg += '  \u2022 ' + u.name + ': ' + u.title + '\n';
  }
  msg += '\n';
}

if (report.medium_updates.length > 0) {
  msg += '\ud83d\udcc8 MEDIUM:\n';
  for (const u of report.medium_updates.slice(0, 10)) {
    msg += '  \u2022 ' + u.name + ': ' + u.title + '\n';
  }
  if (report.medium_updates.length > 10) {
    msg += '  ... and ' + (report.medium_updates.length - 10) + ' more\n';
  }
  msg += '\n';
}

msg += '\ud83d\udccb Full report: competitor-research-results.json';

return [{ json: { telegram_message: msg, discord_message: msg, report } }];

const report = $input.first().json.report;
const fs = require('fs');
const path = '/tmp/competitor-tracker-fix/competitor-research-results.json';
fs.writeFileSync(path, JSON.stringify(report, null, 2));
return [{ json: { status: 'saved', path, updates: report.total_updates } }];

const items = $input.all();
const results = [];

for (const item of items) {
  const comp = { ...item.json };
  comp.commits = [];
  comp.releases = [];
  comp.prs = [];
  comp.issues = [];
  comp.stars = 0;
  comp.changelog_changed = false;
  results.push({ json: comp });
}

return results;
